\pard\fi0\li0\ql\ri0\sb0\sa0\itap0 \plain \f1\lang1033\fs24 2., Bll. 74\plain \f1\super\lang1033\fs24 a \plain \f1\lang1033\fs24 \endash 136\plain \f1\super\lang1033\fs24 b\plain \f1\lang1033\fs24  Erl\u228 \'e4uterungsschrift eines Unbekannten \u252 \'fcber die beiden vorangehenden B\u252 \'fcchern {\field{\*\fldinst HYPERLINK "hida://bezper[0].4100/?u"}{\fldrslt \plain \f1\lang1033\fs24\chcbpat17 Priscians}}\plain \f1\lang1033\fs24 . Prolog: {\field{\*\fldinst HYPERLINK "hida://5650[0].5666l/?u"}{\fldrslt \plain \f1\i\lang1033\fs24\chcbpat17 Venite fili ad me timorem domini docebo vos}}\plain \f1\i\lang1033\fs24 \u8230 \'85.\plain \f1\lang1033\fs24  A: \plain \f1\i\lang1033\fs24 Quoniam in. Iste liber cuius subiectum est\u8230 \'85 \plain \f1\lang1033\fs24 Die Erl\u228 \'e4uterung zum ersten Buche schliesst auf Bl. 127\plain \f1\super\lang1033\fs24 a\plain \f1\lang1033\fs24 : \plain \f1\i\lang1033\fs24 Explicit hoc totum, infunde dare mihi potum. \plain \f1\lang1033\fs24 Daran schliesst die Er\u228 \'e4uterung des zweiten Buches: \plain \f1\i\lang1033\fs24 In superiori vero libro. Nota primo materialiter (?) \u8230 \'85 \plain \f1\lang1033\fs24 bricht aber schon mit den Worten aus Priscian \plain \f1\i\lang1033\fs24 Itaque apud Grecos\plain \f1\lang1033\fs24  ab.}

{\rtf1\ansi\ansicpg0\uc1\deff0\deflang0\deflangfe0{\fonttbl{\f0\fnil\fcharset1 Arial;}{\f1\fnil\fcharset0 Times New Roman;}{\f2\fnil\fcharset1 @Arial Unicode MS;}{\f3\fnil\fcharset1 Times New Roman;}}{\colortbl;\red0\green0\blue0;\red0\green0\blue255;\red0\green255\blue255;\red0\green255\blue0;\red255\green0\blue255;\red255\green0\blue0;\red255\green255\blue0;\red255\green255\blue255;\red0\green0\blue128;\red0\green128\blue128;\red0\green128\blue0;\red128\green0\blue128;\red128\green0\blue0;\red128\green128\blue0;\red128\green128\blue128;\red192\green192\blue192;\red204\green238\blue221;}

\uc1
\pard\fi0\li0\ql\ri0\sb0\sa0\itap0 \plain \f1\lang1033\fs24 3., Bll. 137\plain \f1\super\lang1033\fs24 a\plain \f1\lang1033\fs24 -184\plain \f1\super\lang1033\fs24 b\plain \f1\lang1033\fs24 . {\field{\*\fldinst HYPERLINK "hida://bezper[0].4100/?u"}{\fldrslt \plain \f1\lang1033\fs24\chcbpat17 Eberhardus Bethuniensis}}\plain \f1\lang1033\fs24 , {\field{\*\fldinst HYPERLINK "hida://bezwrk[0].6930/?u"}{\fldrslt \plain \f1\lang1033\fs24\chcbpat17 Laborintus cum lectura}}\plain \f1\lang1033\fs24 . In der lectura auf Bl 137\plain \f1\super\lang1033\fs24 b\plain \f1\lang1033\fs24  steht: \plain \f1\i\lang1033\fs24 Laborintus per magistrum Ebrardum rectorem scholarium Bremensium editus\plain \f1\lang1033\fs24 . Auf dem Vorderdeckel steht: \plain \f1\i\lang1033\fs24 Laborintus cum lectura, \plain \f1\lang1033\fs24 Ueberschrift fehlt. Laborintus A: \plain \f1\i\lang1033\fs24 Pigerius me traxit amor\plain \f1\lang1033\fs24 . E: \plain \f1\i\lang1033\fs24 Ex omni parte mala sunt vicina petentis. \plain \f1\lang1033\fs24 Lectura A: {\field{\*\fldinst HYPERLINK "hida://5650[0].5666l/?u"}{\fldrslt \plain \f1\i\lang1033\fs24\chcbpat17 Dabo vobis os et sapienciam}}\plain \f1\i\lang1033\fs24 .\plain \f1\lang1033\fs24  E: \plain \f1\i\lang1033\fs24 doleat solamen etc. Et sic restat nune finis huius Laborinti. Deo laus. \plain \f1\lang1033\fs24 Gedruckt ohne die Lectura in Policarpi Leyseri. Historia poetarum et poematum medii aevi. Halae 1741 S.795-854.}

